import Foundation

enum NetworkError: Error {
    case invalidResponse
    case decodingError(Error)
    case requestError(Error)
}

func fetch<T: Decodable>(_ type: T.Type, from url: URL) async -> Result<T, NetworkError> {
    do {
        let (data, response) = try await URLSession.shared.data(from: url)

        guard let httpResponse = response as? HTTPURLResponse, 
              (200...299).contains(httpResponse.statusCode) else {
            return.failure(.invalidResponse)
        }

        do {
            let decodedData = try JSONDecoder().decode(T.self, from: data)
            return.success(decodedData)
        } catch {
            return.failure(.decodingError(error))
        }
    } catch {
        return.failure(.requestError(error))
    }
}

// MARK: - Usage Example

struct User: Codable {
    let id: Int
    let name: String
}

async func example() {
    guard let url = URL(string: "https://jsonplaceholder.typicode.com/users/1") else { return }

    let result: Result<User, NetworkError> = await fetch(User.self, from: url)

    switch result {
    case.success(let user):
        print("User: \(user.name)")
    case.failure(let error):
        print("Error: \(error)")
    }
}
